// math.js
export const PI = 3.14;
export function add(a, b) { return a + b; }

// app.js
import { PI, add } from './math.js';
console.log(add(PI, 1));  // 4.14

// math.js — 导出
export const PI = 3.14;
export function add(a, b) { return a + b; }

// app.js — 导入（名字必须匹配）
import { PI, add } from './math.js';
console.log(PI, add(1, 2));  // 3.14 3

// 重命名导入
import { add as sum } from './math.js';
sum(1, 2);  // 3

// ① 命名导入 — 名字必须匹配
import { PI, add } from './math.js';

// ② 默认导入 — 名字随意取
import myFunc from './math.js';
// math.js: export default function() {}

// 混合：默认 + 命名
import React, { useState, useEffect } from 'react';

// ③ 命名空间导入 — 整体作为对象
import * as math from './math.js';
math.add(1, 2);  // 3
math.PI;         // 3.14

// ④ 副作用导入 — 只为执行模块
import './polyfill.js';
import './styles.css';

// 按需加载，常用于路由懒加载
const module = await import('./math.js');
module.add(1, 2);  // 3

// React 路由懒加载示例
const LazyComp = React.lazy(
  () => import('./LazyComp')
);

// ① 命名导出 — 可导出多个
export const PI = 3.14;
export function add(a, b) { return a + b; }
// 或：export { PI, add };

// ② 默认导出 — 每个模块只能一个
export default function add(a, b) {
  return a + b;
}
// 导入时名字随意取

// utils/index.js
export { PI, add } from './math.js';
export { format } from './format.js';
export * from './constants.js';

// 使用方
import { PI, add, format } from './utils';

// math.js — 导出
const PI = 3.14;
function add(a, b) { return a + b; }
module.exports = { PI, add };

// app.js — 导入
const { PI, add } = require('./math.js');
console.log(PI, add(1, 2));  // 3.14 3

// 动态加载
if (needMath) {
  const math = require('./math.js');
}

sections.text:
CommonJS 导出的是值的拷贝（快照）。原模块的值变化不会影响已导入的副本。这是 CJS 和 ESM 的核心差异。

// math.js
let count = 0;
setInterval(() => count++, 1000);
module.exports = { count };  // 拷贝，永远是 0

// ESM 版本用 export { count }，导入方会看到更新。

**互操作陷阱**：ESM 中可以用 `import` 引入 CJS 模块（只有 default），但 CJS 中不能用 `require` 引入 ESM 模块。混用时容易踩坑。

// ESM 引入 CJS（OK）
import pkg from 'cjs-package';

// CJS 引入 ESM（❌ 报错）
const esm = require('esm-package');  // 必须用 await import()

