// 现在可以用 import/export
import fs from 'fs';
const data = JSON.parse(fs.readFileSync('data.json'));

// ESM
import { x } from './m';
import x from './m';       // default
import * as ns from './m';
const m = await import('./m');

// CommonJS
const { x } = require('./m');
const m = require('./m');
module.exports = { x };
exports.x = x;
